export interface Student {
  id: string;
  subjects: string[];
}

export interface SubjectStats {
  name: string;
  count: number;
  students: string[];
}

export interface ScheduleSlot {
  id: number;
  dayName: string; // "Dilluns", "Dimarts", "Dijous"
  timeRange: string; // "15:00 - 16:30"
  weekIndex: number;
  dayIndex: number; // 0=Mon, 1=Tue, 2=Thu
  slotInDay: number; // 0 or 1 (for Tuesday)
}

export interface ScheduledExam {
  subject: string;
  slotId: number;
  students: string[];
}

export type ScheduleResult = {
  schedule: ScheduledExam[];
  totalDays: number;
  slots: ScheduleSlot[];
  unassignable: string[];
};

import { Student, SubjectStats } from '../types';

export const parseRawData = (rawData: string): { students: Student[]; subjectStats: SubjectStats[] } => {
  const lines = rawData.trim().split('\n').map(l => l.trim()).filter(l => l.length > 0);

  const students: Student[] = [];
  const subjectMap: Record<string, Set<string>> = {};

  let currentHeaders: string[] | null = null;

  for (const line of lines) {
    // Basic CSV/TSV parsing
    const parts = line.split(/\t+/).map(p => p.trim());

    // Detect header line (contains subject names usually)
    // Heuristic: If it has "CATALÀ" or "ALUMNE" or "COLUMN", it's a header
    const upperLine = line.toUpperCase();
    if (upperLine.includes('CATALÀ') || upperLine.includes('CASTELLÀ')) {
      currentHeaders = parts;
      continue;
    }

    if (!currentHeaders) continue;

    // Check if it's a data line (starts with a number)
    const id = parts[0];
    if (!id || isNaN(parseInt(id))) continue; // Skip empty or non-numeric IDs

    const studentId = id;
    const studentSubjects: string[] = [];

    // Iterate columns (skipping index 0 which is ID)
    for (let i = 1; i < parts.length; i++) {
      if (i >= currentHeaders.length) break;

      const val = parts[i].toUpperCase();
      const subjectName = currentHeaders[i].toUpperCase();

      // Check for TRUE or non-empty indicator
      if (val === 'TRUE' || val === 'VERITAT' || val === '1' || val === 'SÍ') {
        studentSubjects.push(subjectName);

        if (!subjectMap[subjectName]) {
          subjectMap[subjectName] = new Set();
        }
        subjectMap[subjectName].add(studentId);
      }
    }

    if (studentSubjects.length > 0) {
      students.push({
        id: studentId,
        subjects: studentSubjects
      });
    }
  }

  // Convert map to array and sort by student count (descending) - hardest to schedule first
  const subjectStats: SubjectStats[] = Object.entries(subjectMap).map(([name, studentSet]) => ({
    name,
    count: studentSet.size,
    students: Array.from(studentSet)
  })).sort((a, b) => b.count - a.count);

  return { students, subjectStats };
};

import { ScheduleResult, ScheduleSlot, ScheduledExam, SubjectStats } from '../types';

// Constants for slot logic
const SLOT_DURATION_MIN = 90; // 1.5 hours

// Helper to generate infinite sequence of slots
const generateSlot = (globalIndex: number): ScheduleSlot => {
  // Pattern: Mon(1), Tue(2), Thu(1) -> 4 slots per week
  const slotsPerWeek = 4;
  const weekIndex = Math.floor(globalIndex / slotsPerWeek);
  const slotInWeek = globalIndex % slotsPerWeek;

  let dayName = '';
  let timeRange = '';
  let dayIndex = 0; // 0=Mon, 1=Tue, 2=Thu
  let slotInDay = 0;

  switch (slotInWeek) {
    case 0: // Monday
      dayName = 'Dilluns';
      timeRange = '15:00 - 16:30';
      dayIndex = 0;
      slotInDay = 0;
      break;
    case 1: // Tuesday Slot 1
      dayName = 'Dimarts';
      timeRange = '15:00 - 16:30';
      dayIndex = 1;
      slotInDay = 0;
      break;
    case 2: // Tuesday Slot 2
      dayName = 'Dimarts';
      timeRange = '16:30 - 18:00';
      dayIndex = 1;
      slotInDay = 1;
      break;
    case 3: // Thursday
      dayName = 'Dijous';
      timeRange = '15:00 - 16:30';
      dayIndex = 2;
      slotInDay = 0;
      break;
  }

  return {
    id: globalIndex,
    dayName,
    timeRange,
    weekIndex,
    dayIndex,
    slotInDay
  };
};

// Check if Subject A and Subject B clash based on hard constraints
const isDayIncompatible = (subA: string, subB: string): boolean => {
  const a = subA.toUpperCase();
  const b = subB.toUpperCase();

  const mathGroup = ['MATES', 'MATES CS', 'MATEMÀTIQUES'];
  const spanishGroup = ['CASTELLÀ', 'LLENGUA CASTELLANA'];

  const physicsGroup = ['FÍSICA'];
  const chemGroup = ['QUÍMICA'];

  // Check Math vs Spanish
  const isMathA = mathGroup.some(m => a.includes(m));
  const isSpanA = spanishGroup.some(s => a.includes(s));
  const isMathB = mathGroup.some(m => b.includes(m));
  const isSpanB = spanishGroup.some(s => b.includes(s));

  if ((isMathA && isSpanB) || (isSpanA && isMathB)) return true;

  // Check Physics vs Chemistry
  const isPhysA = physicsGroup.some(p => a.includes(p));
  const isChemA = chemGroup.some(c => a.includes(c));
  const isPhysB = physicsGroup.some(p => b.includes(p));
  const isChemB = chemGroup.some(c => b.includes(c));

  if ((isPhysA && isChemB) || (isChemA && isPhysB)) return true;

  return false;
};

export const generateSchedule = (subjectStats: SubjectStats[]): ScheduleResult => {
  const schedule: ScheduledExam[] = [];
  const unassignable: string[] = [];
  const usedSlots: ScheduleSlot[] = [];

  // We will iterate through sorted subjects
  for (const subject of subjectStats) {
    let assigned = false;
    let slotIndex = 0;

    // Try to find a slot
    // Safety break after 50 slots (approx 12 weeks, unlikely to exceed)
    while (!assigned && slotIndex < 50) {
      const currentSlot = generateSlot(slotIndex);

      // 1. Check for Student Conflicts in this exact slot
      // Does any student in this subject already have an exam in this slot?
      const studentConflict = subject.students.some(studentId => {
        return schedule.some(existingExam => 
          existingExam.slotId === currentSlot.id && 
          existingExam.students.includes(studentId)
        );
      });

      if (studentConflict) {
        slotIndex++;
        continue;
      }

      // 2. Check for Day-Level Hard Constraints (Math/Spanish, Phys/Chem)
      // Check against all other exams scheduled on this same "Day" (Week + DayIndex)
      const uniqueDayId = `${currentSlot.weekIndex}-${currentSlot.dayIndex}`;

      const dayConflict = schedule.some(existingExam => {
        const existingSlot = generateSlot(existingExam.slotId);
        const existingDayId = `${existingSlot.weekIndex}-${existingSlot.dayIndex}`;

        if (existingDayId === uniqueDayId) {
          // It's the same day. Are the subjects incompatible?
          return isDayIncompatible(subject.name, existingExam.subject);
        }
        return false;
      });

      if (dayConflict) {
        slotIndex++;
        continue;
      }

      // If we got here, it's valid
      schedule.push({
        subject: subject.name,
        slotId: currentSlot.id,
        students: subject.students
      });

      // Track used slots for metadata
      if (!usedSlots.some(s => s.id === currentSlot.id)) {
        usedSlots.push(currentSlot);
      }

      assigned = true;
    }

    if (!assigned) {
      unassignable.push(subject.name);
    }
  }

  // Calculate total distinct days used
  const uniqueDays = new Set(schedule.map(s => {
    const slot = generateSlot(s.slotId);
    return `${slot.weekIndex}-${slot.dayIndex}`;
  }));

  // Sort used slots for display
  usedSlots.sort((a, b) => a.id - b.id);

  return {
    schedule,
    totalDays: uniqueDays.size,
    slots: usedSlots,
    unassignable
  };
};

