export const generateSchedule = (subjectStats: SubjectStats[]): ScheduleResult => {
  // Strategy 1: Sort by Student Count (Descending) - Traditional "Hardest First"
  const byCount = [...subjectStats].sort((a, b) => b.count - a.count);

  // Strategy 2: Sort by "Conflict Degree" (sum of shared students with other subjects)
  // This prioritizes subjects that are most entangled with others.
  const conflictScores = new Map<string, number>();
  subjectStats.forEach(subA => {
    let score = 0;
    subjectStats.forEach(subB => {
      if (subA.name === subB.name) return;
      // Count intersection
      const shared = subA.students.filter(s => subB.students.includes(s)).length;
      score += shared;
    });
    conflictScores.set(subA.name, score);
  });

  const byConflict = [...subjectStats].sort((a, b) => {
    const scoreA = conflictScores.get(a.name) || 0;
    const scoreB = conflictScores.get(b.name) || 0;
    if (scoreB !== scoreA) return scoreB - scoreA;
    return b.count - a.count; // tie-break with count
  });

  // Collect candidates
  let candidates: ScheduleResult[] = [];

  candidates.push(runSchedulerAttempt(byCount));
  candidates.push(runSchedulerAttempt(byConflict));

  // Strategy 3: Random Restarts (Monte Carlo)
  // Try 500 random permutations weighted slightly by count to find better packings
  // Actually, pure shuffle of the top contenders often works well.
  for (let i = 0; i < 500; i++) {
    const shuffled = [...subjectStats].sort(() => Math.random() - 0.5);
    candidates.push(runSchedulerAttempt(shuffled));
  }

  // Pick the best result
  // Criteria: 
  // 1. Min unassignable (must be 0 ideally)
  // 2. Min maxSlotId (earliest finish time)

  candidates.sort((a, b) => {
    if (a.unassignable.length !== b.unassignable.length) {
      return a.unassignable.length - b.unassignable.length;
    }

    // Get max slot ID for each
    const maxA = a.slots.length > 0 ? a.slots[a.slots.length - 1].id : 0;
    const maxB = b.slots.length > 0 ? b.slots[b.slots.length - 1].id : 0;

    return maxA - maxB;
  });

  return candidates[0];
};

