  let timeRange = '';
  let dayIndex = 0; // 0=Mon, 1=Tue, 2=Thu
  let slotInDay = 0;

  switch (slotInWeek) {
    case 0: // Monday
      dayName = 'Dilluns';
      timeRange = '15:00 - 16:30';
