import { ScheduleResult, ScheduleSlot, ScheduledExam, SubjectStats } from '../types';

// Constants for slot logic
// const SLOT_DURATION_MIN = 90; // Moved to parameter

// Helper to generate infinite sequence of slots
const generateSlot = (globalIndex: number, duration: 60 | 90): ScheduleSlot => {
  let dayName = '';
  let timeRange = '';
  let dayIndex = 0; // 0=Mon, 1=Tue, 2=Thu
  let slotInDay = 0;
  let weekIndex = 0;

  if (duration === 90) {
    // 90 MINUTE LOGIC (ORIGINAL)
    // Pattern: Mon(1), Tue(2), Thu(1) -> 4 slots per week
    const slotsPerWeek = 4;
    weekIndex = Math.floor(globalIndex / slotsPerWeek);
    const slotInWeek = globalIndex % slotsPerWeek;

    switch (slotInWeek) {
      case 0: // Monday
        dayName = 'Dilluns';
        timeRange = '15:00 - 16:30';
        dayIndex = 0;
        slotInDay = 0;
        break;
      case 1: // Tuesday Slot 1
        dayName = 'Dimarts';
        timeRange = '15:00 - 16:30';
        dayIndex = 1;
        slotInDay = 0;
        break;
      case 2: // Tuesday Slot 2
        dayName = 'Dimarts';
        timeRange = '16:30 - 18:00';
        dayIndex = 1;
        slotInDay = 1;
        break;
      case 3: // Thursday
        dayName = 'Dijous';
        timeRange = '15:00 - 16:30';
        dayIndex = 2;
        slotInDay = 0;
        break;
    }
  } else {
    // 60 MINUTE LOGIC
    // Pattern: Mon(2), Tue(3), Thu(2) -> 7 slots per week
    const slotsPerWeek = 7;
    weekIndex = Math.floor(globalIndex / slotsPerWeek);
    const slotInWeek = globalIndex % slotsPerWeek;

    switch (slotInWeek) {
      case 0: // Mon 1
        dayName = 'Dilluns';
        timeRange = '15:00 - 16:00';
        dayIndex = 0;
        slotInDay = 0;
        break;
      case 1: // Mon 2
        dayName = 'Dilluns';
        timeRange = '16:00 - 17:00';
        dayIndex = 0;
        slotInDay = 1;
        break;
      case 2: // Tue 1
        dayName = 'Dimarts';
        timeRange = '15:00 - 16:00';
        dayIndex = 1;
        slotInDay = 0;
        break;
      case 3: // Tue 2
        dayName = 'Dimarts';
        timeRange = '16:00 - 17:00';
        dayIndex = 1;
        slotInDay = 1;
        break;
      case 4: // Tue 3
        dayName = 'Dimarts';
        timeRange = '17:00 - 18:00';
        dayIndex = 1;
        slotInDay = 2;
        break;
      case 5: // Thu 1
        dayName = 'Dijous';
        timeRange = '15:00 - 16:00';
        dayIndex = 2;
        slotInDay = 0;
        break;
      case 6: // Thu 2
        dayName = 'Dijous';
        timeRange = '16:00 - 17:00';
        dayIndex = 2;
        slotInDay = 1;
        break;
    }
  }

  return {
    id: globalIndex,
    dayName,
    timeRange,
    weekIndex,
    dayIndex,
    slotInDay
  };
};

